cd "C:\Users\bhirani\AppData\Local\Temp\3\claude\c--Code-dterziev-CoreClaw\e2f6752b-555b-4db9-ab95-752506132736\scratchpad\marqueeservice" && cat ../baseline-packages.json | python3 -c "
import json, sys
data = json.load(sys.stdin)
pkgs = {}
for proj in data.get('projects', []):
    pname = proj['path'].split('/')[-1].replace('.csproj','')
    for fw in proj.get('frameworks', []):
        for pkg in fw.get('topLevelPackages', []):
            name = pkg['id']
            ver = pkg.get('requestedVersion', pkg.get('resolvedVersion',''))
            if name not in pkgs:
                pkgs[name] = {}
            if ver not in pkgs[name]:
                pkgs[name][ver] = []
            pkgs[name][ver].append(pname)

# Show conflicts
print('=== CONFLICTS ===')
for name, vers in sorted(pkgs.items()):
    if len(vers) > 1:
        print(f'{name}: {dict(vers)}')

print()
print('=== ALL PACKAGES ===')
for name, vers in sorted(pkgs.items()):
    all_vers = list(vers.keys())
    print(f'{name}: {all_vers}')
"

